mom_patterns.previous_month_measure:
// Method 1: PREVIOUSMONTH — recommended for month-granularity snapshots
VulnCount PM =
    CALCULATE(
        [VulnCount],
        PREVIOUSMONTH('DateTable'[Date])
    )

// Method 2: DATEADD — equivalent, but explicit about the interval
VulnCount PM =
    CALCULATE(
        [VulnCount],
        DATEADD('DateTable'[Date], -1, MONTH)
    )

qoq_patterns.previous_quarter_measure:
// Method 1: PREVIOUSQUARTER
VulnCount PQ =
    CALCULATE(
        [VulnCount],
        PREVIOUSQUARTER('DateTable'[Date])
    )

// Method 2: DATEADD
VulnCount PQ =
    CALCULATE(
        [VulnCount],
        DATEADD('DateTable'[Date], -1, QUARTER)
    )

yoy_patterns.sameperiodlastyear_measure:
// SAMEPERIODLASTYEAR — shifts the entire current filter context back exactly 1 year
VulnCount LY =
    CALCULATE(
        [VulnCount],
        SAMEPERIODLASTYEAR('DateTable'[Date])
    )

yoy_patterns.previousyear_measure:
// PREVIOUSYEAR — returns ALL dates in the prior calendar year (Jan 1 – Dec 31)
// Use this for full-year YTD comparisons, not for month-by-month columns
VulnCount PY =
    CALCULATE(
        [VulnCount],
        PREVIOUSYEAR('DateTable'[Date])
    )

yoy_patterns.dateadd_year_measure:
// DATEADD for YoY — same result as SAMEPERIODLASTYEAR for most cases
VulnCount LY =
    CALCULATE(
        [VulnCount],
        DATEADD('DateTable'[Date], -1, YEAR)
    )

running_total_patterns.ytd_measure:
// Year-to-Date using TOTALYTD (shorthand)
VulnCount YTD =
    TOTALYTD([VulnCount], 'DateTable'[Date])
// Equivalent to:
// CALCULATE([VulnCount], DATESYTD('DateTable'[Date]))

running_total_patterns.fiscal_ytd:
// Fiscal YTD — fiscal year ends September 30
VulnCount FYTD =
    TOTALYTD([VulnCount], 'DateTable'[Date], "09-30")
// The third argument is the fiscal year end date in MM-DD format

running_total_patterns.running_total_alltime:
// Cumulative total from the very first period to current
VulnCount Running Total =
VAR _CurrentMonthKey = MAX('DateTable'[MonthSort])   -- e.g. 202603
RETURN
    CALCULATE(
        [VulnCount],
        FILTER(
            ALL('DateTable'),
            'DateTable'[MonthSort] <= _CurrentMonthKey
        )
    )
// Uses MonthSort (integer YYYYMM) for correct ordering of text-keyed rows

missing_period_handling.lastnonblank_pattern:
// Show the last known value when a month has no snapshot
// Use this as the 'current value' measure when data may be missing
VulnCount Safe =
    CALCULATE(
        LASTNONBLANK(
            'DateTable'[Date],
            CALCULATE(SUM(SecuritySnapshots[Value]))
        )
    )
// LASTNONBLANK returns the last date where the expression is non-blank,
// then evaluates the expression at that date.

missing_period_handling.coalesce_pattern:
// Simpler: use COALESCE to substitute 0 or a prior value when blank
VulnCount Or Zero =
    COALESCE([VulnCount], 0)

// For MoM when current month might be missing:
MoM Change Safe =
VAR _Current = COALESCE([VulnCount], 0)
VAR _Prior   = COALESCE([VulnCount PM], 0)
RETURN
    IF(_Prior = 0, BLANK(), DIVIDE(_Current - _Prior, _Prior))
// Note: using 0 can make MoM changes look dramatic; prefer BLANK() for missing months in trend charts

missing_period_handling.detecting_missing_periods:
// Diagnostic measure to identify which months have no data
HasData =
    IF(ISBLANK([VulnCount]), "Missing", "Present")
// Add to a table visual with Month on rows to audit coverage

multi_metric_pattern.metric_dimension_measures:
// Assumes tall fact table: SecuritySnapshots[MetricName], SecuritySnapshots[Value]
// One base measure works for ALL metrics when MetricName is on matrix rows:
Metric Value = SUM(SecuritySnapshots[Value])

// MoM for ALL metrics in one measure:
Metric MoM Change % =
VAR _Current = [Metric Value]
VAR _Prior   = CALCULATE([Metric Value], PREVIOUSMONTH('DateTable'[Date]))
RETURN
    IF(ISBLANK(_Prior) || _Prior = 0, BLANK(), DIVIDE(_Current - _Prior, ABS(_Prior)))

// Put MetricName on matrix rows, MonthYear on columns
// Both measures adapt to each metric row automatically
